DROP TABLE IF EXISTS `appointments`;
CREATE TABLE `appointments` (
  `id` int(10) unsigned NOT NULL AUTO_INCREMENT,
  `procedure_id` varchar(120) NOT NULL,
  `procedure_name` varchar(180) NOT NULL,
  `patient_name` varchar(160) NOT NULL,
  `email` varchar(180) DEFAULT NULL,
  `phone` varchar(60) NOT NULL,
  `appointment_date` date NOT NULL,
  `appointment_time` time NOT NULL,
  `notes` text DEFAULT NULL,
  `status` enum('Pending','Confirmed','Completed','Cancelled','No Show') NOT NULL DEFAULT 'Pending',
  `assigned_staff` varchar(160) DEFAULT NULL,
  `source` enum('online','staff') NOT NULL DEFAULT 'online',
  `recorded_by` int(11) DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `idx_appointments_schedule` (`appointment_date`,`appointment_time`),
  KEY `idx_appointments_status` (`status`),
  KEY `idx_appointments_procedure` (`procedure_id`),
  KEY `idx_appointments_recorded_by` (`recorded_by`)
) ENGINE=InnoDB AUTO_INCREMENT=25 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

