DROP TABLE IF EXISTS `consultation_image_records`;
CREATE TABLE `consultation_image_records` (
  `id` int(10) unsigned NOT NULL AUTO_INCREMENT,
  `procedure_id` varchar(120) DEFAULT NULL,
  `procedure_name` varchar(180) NOT NULL,
  `original_image_path` varchar(255) DEFAULT NULL,
  `processed_image_path` varchar(255) DEFAULT NULL,
  `processing_status` enum('Completed','Failed','Pending','Deleted') NOT NULL DEFAULT 'Completed',
  `handled_by` varchar(120) DEFAULT NULL,
  `notes` text DEFAULT NULL,
  `date_processed` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `idx_records_procedure` (`procedure_name`),
  KEY `idx_records_status` (`processing_status`),
  KEY `idx_records_date` (`date_processed`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

DROP TABLE IF EXISTS `image_processing_settings`;
CREATE TABLE `image_processing_settings` (
  `id` tinyint(3) unsigned NOT NULL DEFAULT 1,
  `processing_enabled` tinyint(1) NOT NULL DEFAULT 1,
  `default_brightness` int(11) NOT NULL DEFAULT 100,
  `default_contrast` int(11) NOT NULL DEFAULT 105,
  `default_sharpness` int(11) NOT NULL DEFAULT 110,
  `smoothing_level` int(11) NOT NULL DEFAULT 20,
  `output_quality` int(11) NOT NULL DEFAULT 90,
  `max_upload_size` varchar(40) NOT NULL DEFAULT '10 MB',
  `allowed_file_types` varchar(120) NOT NULL DEFAULT 'JPG, PNG, JPEG',
  `output_folder` varchar(255) NOT NULL DEFAULT 'processed_uploads/',
  `resize_limit` varchar(40) NOT NULL DEFAULT '1600 px',
  `retention_period` varchar(40) NOT NULL DEFAULT '90 days',
  `show_disclaimer` tinyint(1) NOT NULL DEFAULT 1,
  `disclaimer_text` text DEFAULT NULL,
  `script_mappings` text DEFAULT NULL,
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

INSERT INTO `image_processing_settings` (`id`, `processing_enabled`, `default_brightness`, `default_contrast`, `default_sharpness`, `smoothing_level`, `output_quality`, `max_upload_size`, `allowed_file_types`, `output_folder`, `resize_limit`, `retention_period`, `show_disclaimer`, `disclaimer_text`, `script_mappings`, `updated_at`) VALUES ('1', '1', '100', '105', '110', '20', '90', '10 MB', 'JPG, PNG, JPEG', 'processed_uploads/', '1600 px', '90 days', '1', 'Image processing previews are for awareness and documentation only. Results may vary per patient.', 'CO2 Fractional Laser + Dermapen: process_co2_dermapen.py\r\nFace Slimming Package: process_face_slimming.py\r\nDiamond Peel with Facial: process_diamond_peel.py\r\nUndereye and Lip Filler: process_undereye_lip_filler.py\r\nPICO Carbon Laser Facial: process_pico_carbon_laser.py\r\nLip Filler, Chin Filler, and Jawtox: process_lip_chin_jawtox.py\r\nGeneral Skin Assessment: process_general_skin_assessment.py', '2026-05-24 22:42:05');

