DROP TABLE IF EXISTS `procedures`;
CREATE TABLE `procedures` (
  `id` int(10) unsigned NOT NULL AUTO_INCREMENT,
  `procedure_name` varchar(180) NOT NULL,
  `category` varchar(80) NOT NULL,
  `short_description` text NOT NULL,
  `full_description` text DEFAULT NULL,
  `benefits` text DEFAULT NULL,
  `preparation_guidelines` text DEFAULT NULL,
  `aftercare_instructions` text DEFAULT NULL,
  `session_duration` varchar(80) DEFAULT NULL,
  `recommended_sessions` varchar(80) DEFAULT NULL,
  `procedure_price` varchar(80) DEFAULT NULL,
  `processing_script` varchar(160) DEFAULT NULL,
  `status` enum('Active','Inactive') NOT NULL DEFAULT 'Active',
  `procedure_image` varchar(255) DEFAULT NULL,
  `sort_order` int(10) unsigned NOT NULL DEFAULT 0,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `idx_procedures_status` (`status`),
  KEY `idx_procedures_category` (`category`),
  KEY `idx_procedures_sort_order` (`sort_order`)
) ENGINE=InnoDB AUTO_INCREMENT=19 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

INSERT INTO `procedures` (`id`, `procedure_name`, `category`, `short_description`, `full_description`, `benefits`, `preparation_guidelines`, `aftercare_instructions`, `session_duration`, `recommended_sessions`, `procedure_price`, `processing_script`, `status`, `procedure_image`, `sort_order`, `created_at`, `updated_at`) VALUES ('1', 'CO2 Fractional Laser + Dermapen', 'Laser', 'Combined resurfacing and microneedling for texture, scars, and rejuvenation.', 'A combined procedure plan used for patient education and treatment documentation.', 'Improves appearance of texture, scarring, and uneven tone.', 'Avoid harsh actives and disclose recent procedures.', 'Use sun protection and follow clinic aftercare.', '45-90 minutes', '3-5 sessions', NULL, NULL, 'Active', NULL, '4', '2026-05-24 22:40:10', '2026-05-26 18:07:29');
INSERT INTO `procedures` (`id`, `procedure_name`, `category`, `short_description`, `full_description`, `benefits`, `preparation_guidelines`, `aftercare_instructions`, `session_duration`, `recommended_sessions`, `procedure_price`, `processing_script`, `status`, `procedure_image`, `sort_order`, `created_at`, `updated_at`) VALUES ('2', 'Face Slimming Package', 'Contouring', 'Non-surgical contouring plan for facial definition and balance.', 'A contouring package for facial slimming awareness and planning.', 'sdfafsafsd', 'Avoid alcohol and disclose medication history.', 'Avoid massage unless instructed by staff.', '30-60 minutes', '1-3 sessions', NULL, NULL, 'Active', NULL, '3', '2026-05-24 22:40:10', '2026-05-26 18:07:29');
INSERT INTO `procedures` (`id`, `procedure_name`, `category`, `short_description`, `full_description`, `benefits`, `preparation_guidelines`, `aftercare_instructions`, `session_duration`, `recommended_sessions`, `procedure_price`, `processing_script`, `status`, `procedure_image`, `sort_order`, `created_at`, `updated_at`) VALUES ('3', 'Diamond Peel with Facial', 'Facial', 'Gentle exfoliation with cleansing facial care for smoother-looking skin.', 'A facial service combining exfoliation and cleansing steps.', 'Helps remove dull surface buildup and improves skin feel.', 'Arrive with clean skin when possible.', 'Avoid harsh scrubs for several days.', '45-60 minutes', '1-4 sessions', NULL, NULL, 'Active', NULL, '2', '2026-05-24 22:40:10', '2026-05-26 18:08:01');
INSERT INTO `procedures` (`id`, `procedure_name`, `category`, `short_description`, `full_description`, `benefits`, `preparation_guidelines`, `aftercare_instructions`, `session_duration`, `recommended_sessions`, `procedure_price`, `processing_script`, `status`, `procedure_image`, `sort_order`, `created_at`, `updated_at`) VALUES ('4', 'Undereye and Lip Filler', 'Filler', 'Targeted filler service for undereye support and lip enhancement.', 'A filler procedure documented for awareness and consultation review.', 'Supports volume correction and profile balance.', 'Disclose allergies, medication, and previous fillers.', 'Avoid pressure, heat, and strenuous activity as instructed.', '45-75 minutes', '1 session plus review', NULL, NULL, 'Active', NULL, '5', '2026-05-24 22:40:10', '2026-05-24 23:06:44');
INSERT INTO `procedures` (`id`, `procedure_name`, `category`, `short_description`, `full_description`, `benefits`, `preparation_guidelines`, `aftercare_instructions`, `session_duration`, `recommended_sessions`, `procedure_price`, `processing_script`, `status`, `procedure_image`, `sort_order`, `created_at`, `updated_at`) VALUES ('5', 'PICO Carbon Laser Facial', 'Skin Rejuvenation', 'Carbon-assisted laser facial for tone, pores, and brightness.', 'A laser facial option for skin rejuvenation awareness.', 'Improves brightness, oil appearance, and visible pores.', 'Avoid sun exposure before treatment.', 'Use sunscreen and gentle products after treatment.', '45-60 minutes', '3-6 sessions', NULL, NULL, 'Active', NULL, '6', '2026-05-24 22:40:10', '2026-05-24 23:06:44');
INSERT INTO `procedures` (`id`, `procedure_name`, `category`, `short_description`, `full_description`, `benefits`, `preparation_guidelines`, `aftercare_instructions`, `session_duration`, `recommended_sessions`, `procedure_price`, `processing_script`, `status`, `procedure_image`, `sort_order`, `created_at`, `updated_at`) VALUES ('6', 'Lip Filler, Chin Filler, and Jawtox', 'Filler', 'Profile-balancing injectables for lips, chin, and jawline tension.', 'A combined injectable package for consultation documentation.', 'Supports profile harmony and jawline relaxation.', 'Avoid blood-thinning products unless medically required.', 'Avoid heavy exercise and pressure after treatment.', '60-90 minutes', '1 session plus review', NULL, NULL, 'Active', NULL, '7', '2026-05-24 22:40:10', '2026-05-24 23:06:44');
