DROP TABLE IF EXISTS `processed_images`;
CREATE TABLE `processed_images` (
  `id` int(10) unsigned NOT NULL AUTO_INCREMENT,
  `procedure_id` varchar(120) NOT NULL,
  `procedure_name` varchar(180) NOT NULL,
  `analysis_type` varchar(80) NOT NULL DEFAULT 'Treatment Visualization',
  `before_image_path` varchar(255) NOT NULL,
  `after_image_path` varchar(255) NOT NULL,
  `metrics_json` longtext DEFAULT NULL,
  `recommendations_json` longtext DEFAULT NULL,
  `handled_by` varchar(160) DEFAULT NULL,
  `handled_by_user_id` int(11) DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `idx_processed_images_procedure` (`procedure_id`),
  KEY `idx_processed_images_created_at` (`created_at`)
) ENGINE=InnoDB AUTO_INCREMENT=79 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

